  ('real-estate-moex-01885', 'real-estate', 'real-estate-moex-101-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '甲公司於A市擁有商業區土地一宗，擬將其分割為兩筆土地，一筆做為辦公大樓使用，另一筆做為百貨 公司使用，以符合商業區土地的經濟效益。今如就前述兩筆土地進行估價，則價格種類為下列何者？', '["正常價格", "特殊價格", "限定價格", "特定價格"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "7df93cdf817f", "answer_pdf_sha1": "3f5da56333ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產估價概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
